const PrintManager = (() => {
  function fmtDate(iso) {
    if (!iso) return '';
    const d = new Date(iso);
    return `${d.getFullYear()}/${String(d.getMonth()+1).padStart(2,'0')}/${String(d.getDate()).padStart(2,'0')}`;
  }

  function maskPass(p) {
    if (!p) return '';
    if (p.length <= 3) return '•'.repeat(p.length);
    return p.slice(0, 1) + '•'.repeat(p.length - 2) + p.slice(-1);
  }

  function esc(value) {
    return String(value ?? '').replace(/[&<>"']/g, ch => ({
      '&': '&amp;',
      '<': '&lt;',
      '>': '&gt;',
      '"': '&quot;',
      "'": '&#39;'
    }[ch]));
  }

  function textUnits(text) {
    return Array.from(text).reduce((sum, ch) => sum + (ch.charCodeAt(0) <= 0x7f ? 1 : 2), 0);
  }

  function splitPrintText(text, maxUnits = 68) {
    const chunks = [];
    let current = '';
    let units = 0;

    for (const ch of Array.from(text)) {
      const unit = textUnits(ch);
      if (current && units + unit > maxUnits) {
        chunks.push(current.trimEnd());
        current = '';
        units = 0;
      }
      current += ch;
      units += unit;
    }

    if (current) chunks.push(current.trimEnd());
    return chunks.length ? chunks : [''];
  }

  function packPrintLines(lines, linesPerRow = 1) {
    const rows = [];
    for (let i = 0; i < lines.length; i += linesPerRow) {
      rows.push(lines.slice(i, i + linesPerRow));
    }
    return rows;
  }

  function historyPrintLines(h, isOther) {
    const label = TYPE_LABEL[h.type] || h.type;
    const lines = [label];

    const creds = [];
    if (h.username) creds.push(`ID: ${h.username}`);
    if (!isOther && h.password) creds.push(`PW: ${h.password}`);
    if (creds.length) lines.push(creds.join('     '));
    if (h.note) {
      const noteLines = String(h.note).split(/\r?\n/);
      noteLines.forEach((line, idx) => {
        lines.push(`${idx === 0 ? 'メモ: ' : ''}${line}`);
      });
    }

    return lines.flatMap(line => splitPrintText(line));
  }

  function historyRowsHTML(history, maxRows = Infinity) {
    const rows = [];

    for (const h of history) {
      if (rows.length >= maxRows) break;

      const isOther = h.type === 'other' || h.type === 'alert' || h.type === 'warning';
      const chunks = packPrintLines(historyPrintLines(h, isOther));
      chunks.forEach((chunkLines, idx) => {
        if (rows.length >= maxRows) return;
        rows.push(`<tr class="${isOther ? 'row-other' : ''}${idx > 0 ? ' row-cont' : ''}">
        <td class="col-date">${idx === 0 ? fmtDate(h.date) : ''}</td>
        <td class="col-hist">${chunkLines.map(esc).join('<br>')}</td>
      </tr>`);
      });
    }

    return rows;
  }

  function printRowsForEntry(entry) {
    const history = [...(entry.history || [])].sort((a, b) => new Date(b.date) - new Date(a.date));
    const description = (entry.description || '').trim();
    const descRows = description
      ? [`<tr class="row-desc">
        <td class="col-date">about</td>
        <td class="col-hist">${esc(description)}</td>
      </tr>`]
      : [];

    return [...descRows, ...historyRowsHTML(history)];
  }

  function expandPrintCards(entries) {
    const maxRows = TOTAL_ROWS + 1;
    return entries.flatMap(entry => {
      const rows = printRowsForEntry(entry);
      const pageCount = Math.max(1, Math.ceil(rows.length / maxRows));

      return Array.from({ length: pageCount }, (_, i) => ({
        ...entry,
        printTitle: pageCount > 1 ? `${entry.title || ''} (${i + 1}/${pageCount})` : entry.title,
        printRows: rows.slice(i * maxRows, (i + 1) * maxRows)
      }));
    });
  }

  const TYPE_LABEL = {
    initial: '初期設定', change: 'PW変更', other: 'その他',
    create: '初期設定', update: 'PW変更', alert: 'その他', warning: 'その他'
  };

  const TOTAL_ROWS = 13;

  function cardFrontHTML(entry) {
    const maxRows = TOTAL_ROWS + 1;
    const printRows = entry.printRows || printRowsForEntry(entry).slice(0, maxRows);
    const blankRows = Array(Math.max(0, maxRows - printRows.length))
      .fill('<tr class="blank-row"><td class="col-date"></td><td class="col-hist"></td></tr>');

    const ownerLine = entry.owner
      ? `<div class="svc-sub">${entry.owner}${entry.type === 'website' && entry.url ? '　' + entry.url : ''}</div>`
      : (entry.type === 'website' && entry.url ? `<div class="svc-sub">${entry.url}</div>` : '');

    return `
    <div class="card-front">
      <div class="punch-col"></div>
      <div class="card-body">
        <div class="card-header">
          <div class="pw-label">password</div>
          <div class="svc-name">${esc(entry.printTitle || entry.title)}</div>
          ${ownerLine}
        </div>
        <div class="header-rule"></div>
        <table class="hist-table">
          <thead><tr>
            <th class="col-date">date</th>
            <th class="col-hist">history</th>
          </tr></thead>
          <tbody>${[...printRows, ...blankRows].join('')}</tbody>
        </table>
        <div class="watermark"></div>
          <div class="card-footer">N's notebook</div>
      </div>
    </div>`;
  }

  function cardBackHTML(entry) {
    const blankRows = Array(TOTAL_ROWS + 1)
      .fill('<tr class="blank-row"><td class="col-memo"></td></tr>')
      .join('');

    return `
    <div class="card-back">
      <div class="card-body">
        <div class="card-header">
          <div class="pw-label">memo</div>
          <div class="svc-name back-title">MEMO</div>
        </div>
        <div class="header-rule"></div>
        <table class="hist-table">
          <thead><tr>
            <th class="col-memo">note</th>
          </tr></thead>
          <tbody>${blankRows}</tbody>
        </table>
        <div class="watermark"></div>
          <div class="card-footer">N's notebook</div>
      </div>
      <div class="punch-col"></div>
    </div>`;
  }

  function getPrintCSS() {
    return `
* { margin:0; padding:0; box-sizing:border-box; }
body { font-family: 'Noto Sans JP','Hiragino Kaku Gothic ProN','Yu Gothic',sans-serif; background:#fff; color:#000; }
@page { size:A4 portrait; margin:0; }

.a4 {
  width:210mm; height:296mm;
  display:grid;
  grid-template-columns:105mm 105mm;
  grid-template-rows:148mm 148mm;
  page-break-after:always;
  position:relative;
  overflow:hidden;
}
.a4:last-child { page-break-after:avoid; }

/* カット目安線 */
.a4::before {
  content:''; position:absolute; left:105mm; top:0; bottom:0;
  border-left:0.2mm dashed #000; pointer-events:none; z-index:10;
}
.a4::after {
  content:''; position:absolute; top:148mm; left:0; right:0;
  border-top:0.2mm dashed #000; pointer-events:none; z-index:10;
}

.slot {
  width:105mm; height:148mm;
  overflow:hidden; position:relative;
}

/* カード共通 */
.card-front, .card-back {
  width:105mm; height:148mm;
  display:flex; flex-direction:row;
}

/* 穴あけ代（front=左、back=右、穴は印刷しない） */
.punch-col {
  width:13mm; flex-shrink:0;
}

/* カード本体 */
.card-body {
  flex:1;
  padding:3mm 3mm 3mm 2mm;
  display:flex; flex-direction:column;
  overflow:hidden;
  position:relative;
}

/* 表面: 右端が切断線 → 右に余白 */
.card-front .card-body { padding-right:7mm; }
/* 裏面: 左端が切断線 → 左に余白 */
.card-back  .card-body { padding-left:7mm; }

/* 上段: 下端が切断線 → 下に余白（外側=上は小さくてよい） */
.slot:nth-child(1) .card-body,
.slot:nth-child(2) .card-body {
  padding-top:3mm;
  padding-bottom:9mm;
}
/* 下段: 上段と同じ配置（コンテンツは上から、N's notebookは絶対配置で下固定） */
.slot:nth-child(3) .card-body,
.slot:nth-child(4) .card-body {
  padding-top:3mm;
  padding-bottom:9mm;
}

/* ヘッダー — 高さ固定で表裏の罫線位置を揃える */
.card-header {
  height:18mm; flex-shrink:0; overflow:hidden;
  margin-bottom:1mm;
  position:relative;
  z-index:1;
}
.pw-label {
  font-size:7pt; font-weight:bold;
  color:#000;
  letter-spacing:0.5pt;
  margin-bottom:0.5mm;
}
.svc-name {
  font-size:20pt; font-weight:bold; color:#000;
  white-space:nowrap; overflow:hidden; text-overflow:ellipsis;
  line-height:1.15;
}
.svc-sub {
  font-size:9pt; font-weight:600; color:#000;
  margin-top:1mm;
  white-space:nowrap; overflow:hidden; text-overflow:ellipsis;
}
.header-rule {
  border-bottom:0.5mm solid #000;
  margin-bottom:0;
  position:relative;
  z-index:1;
}

/* N's notebook 刻印 */
.card-footer {
  position:absolute;
  bottom:5mm; left:0; right:0;
  text-align:center;
  font-family:'Times New Roman', Times, serif;
  font-size:10pt; color:#000;
  font-weight:bold;
  letter-spacing:0.8pt;
  pointer-events:none;
  z-index:1;
}

/* 履歴テーブル */
.hist-table {
  width:100%;
  border-collapse:collapse;
  table-layout:fixed;
  position:relative;
  z-index:1;
}
.hist-table thead th {
  font-size:6.5pt; font-weight:bold; color:#000;
  border-bottom:0.3mm solid #000;
  padding:1mm 1mm 0.8mm;
  text-align:left;
}
.col-date { width:21mm; border-right:0.3mm solid #000; }
.col-hist {
  overflow-wrap:anywhere;
  word-break:break-word;
  white-space:pre;
}
.col-memo { width:100%; }
.back-title { color:#000; }
.hist-table tbody tr {
  border-bottom:0.25mm solid #000;
  height:7.8mm;
  max-height:7.8mm;
}
.hist-table tbody td {
  padding:0.4mm 1.2mm;
  font-size:6pt;
  line-height:3.1mm;
  vertical-align:top;
  overflow:hidden;
}
.row-other td { color:#000; }
.row-desc td {
  font-weight:600;
  color:#000;
}
.row-desc .col-date {
  color:#000;
}

/* フクロウロゴ透かし */
.watermark {
  position:absolute;
  top:50%; left:50%;
  transform:translate(-50%, -50%);
  width:40mm; height:40mm;
  opacity:0.06;
  z-index:0;
  background-image:url('data:image/jpeg;base64,');
  background-size:contain;
  background-repeat:no-repeat;
  background-position:center;
  pointer-events:none;
}
    `;
  }

  function printEntries(entries) {
    // 2エントリーずつ処理: 左列=表, 右列=裏メモ
    const win = window.open('', '_blank');
    const doc = win.document;
    doc.write(`<!DOCTYPE html><html lang="ja"><head><meta charset="UTF-8">
      <title>パスワードカード印刷</title>
      <style>${getPrintCSS()}</style></head><body>`);

    const cards = expandPrintCards(entries);

    for (let i = 0; i < cards.length; i += 2) {
      const a = cards[i]     || null;
      const b = cards[i + 1] || null;

      doc.write(`<div class="a4">`);
      // 左列: 表
      doc.write(`<div class="slot">${a ? cardFrontHTML(a) : ''}</div>`);
      // 右列: 裏メモ（同じエントリのメモ面）
      doc.write(`<div class="slot">${a ? cardBackHTML(a) : ''}</div>`);
      // 左列: 表（2枚目）
      doc.write(`<div class="slot">${b ? cardFrontHTML(b) : ''}</div>`);
      // 右列: 裏メモ（2枚目）
      doc.write(`<div class="slot">${b ? cardBackHTML(b) : ''}</div>`);
      doc.write(`</div>`);
    }

    doc.write(`</body></html>`);
    doc.close();
    setTimeout(() => { win.focus(); win.print(); }, 600);
  }

  return { printEntries };
})();
